            // If pre[i] is greater than the top of the stack, it means pre[i] is a right child
            // of some node. Keep popping from the stack while the top is smaller than pre[i].
            // The last popped element will be the parent of pre[i].
            while (!s.isEmpty() && s.peek() < pre[i]) {
