    public static boolean findDuplicateParenthesis(String str) {
        // Create a stack to hold characters
        Stack<Character> stack = new Stack<>();
        // Iterate through the string expression
        for (char ch : str.toCharArray()) {
            // If the character is a closing parenthesis ')'
            if (ch == ')') {
                // Pop the top of the stack
                char top = stack.pop();
                // Keep track of elements between the matching parentheses
                int elementsInside = 0;
                while (top != '(') {
                    elementsInside++;
                    top = stack.pop();
                }
                // If there are no elements between the parentheses,
                // it's a redundant pair.
                // e.g., ((a+b)) -> the outer pair encloses only '(',
                // which represents the inner sub-expression.
                if (elementsInside < 1) {
                    return true;
                }
            } else {
                // Push the current character onto the stack
                stack.push(ch);
            }
        }
        // No duplicate parentheses were found in the entire expression
        return false;
    }

