    public static long maxDotProduct(int[] A, int[] B, int m, int n) {
        // dp[i][j] will store the maximum dot product of B[0..i-1] and A[0..j-1].
        // Note: The length of A is m, and the length of B is n.
        // We assume m >= n for this algorithm to be meaningful.
        long[][] dp = new long[n + 1][m + 1];
        // The dp table is automatically initialized to 0 in Java,
        // so no explicit initialization is needed.
        // Fill dp table using bottom-up approach
        for (int i = 1; i <= n; i++) {
            for (int j = i; j <= m; j++) {
                // dp[i][j] can be calculated by two cases:
                // 1. Include A[j-1] and B[i-1] in the dot product.
                //    Value = dp[i-1][j-1] + A[j-1] * B[i-1]
                // 2. Do not include A[j-1] in the dot product.
                //    Value = dp[i][j-1]
                // We take the maximum of these two cases.
                // We cast to long during multiplication to prevent potential integer overflow.
                dp[i][j] = Math.max(
                    dp[i - 1][j - 1] + (long)A[j - 1] * B[i - 1],
                    dp[i][j - 1]
                );
            }
        }
        // dp[n][m] contains the maximum dot product of B[0..n-1] and a subsequence of A[0..m-1].
        return dp[n][m];
    }

