        // If all elements are zero, the maximum product is 0.
        if (count_zero == n) {
            return 0;
        }
        // If the number of negative numbers is odd, the product will be negative.
        // To maximize it, we must remove the negative number with the smallest
        // absolute value (which is the largest negative number, max_neg).
        if ((count_neg & 1) != 0) {
