            // the max product is 0 (by choosing the subset containing 0).
            if (count_neg == 1 && count_zero > 0 && (count_zero + count_neg == n)) {
                return 0;
            }
            // Divide the total product by the largest negative number to get the max product.
            prod = prod / max_neg;
        }
        return prod;
