    public static int getTotalNumberOfSequences(int m, int n) {
        // T[i][j] will be storing the number of sequences of length j with max element i.
        // Create a 2D array (table) of size (m+1) x (n+1).
        // In Java, integer arrays are automatically initialized with 0.
        int[][] T = new int[m + 1][n + 1];
        // Fill the table T in a bottom-up manner.
        for (int i = 0; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                // Base case: If max element is 0 or length of sequence is 0,
                // there are no possible sequences.
