    public static int knapSack(int[] val, int[] wt, int n, int W) {
        // dp[i] will be storing the maximum value with knapsack capacity i.
        // In Java, an int array is automatically initialized with zeros.
        int[] dp = new int[W + 1];
        // Iterate through all items
        for (int i = 0; i < n; i++) {
            // Traverse dp array from right to left. This is crucial for the 1D DP
            // approach to ensure that an item is considered at most once per capacity.
            for (int j = W; j >= 0; j--) {
                // Check if the current item's weight is less than or equal to the
                // current capacity 'j'. This corresponds to the Python condition
                // `j - wt[i] >= 0`. The other condition `j - wt[i] < W + 1` is
                // redundant since j <= W and wt[i] is non-negative.
                if (j >= wt[i]) {
                    // dp[j] can be the maximum of two cases:
                    // 1. Not including the current item i: value remains dp[j]
                    // 2. Including the current item i: value is val[i] + dp[j - wt[i]]
                    dp[j] = Math.max(dp[j], val[i] + dp[j - wt[i]]);
                }
            }
        }
        // The final answer is the maximum value for the full knapsack capacity W.
        return dp[W];
    }

