        while (b != 0) {
            // Remove all factors of 2 from 'b'.
            while ((b & 1) == 0) {
                b = b >> 1;
            }
            // Now a and b are both odd.
            // Swap if necessary so that a <= b.
            if (a > b) {
                int temp = a;
                a = b;
                b = temp;
            }
            // b becomes b - a. Since a and b are odd, b - a is even.
            // The next iteration will factor out the powers of 2.
            b = b - a;
        }
        // Restore the common factors of 2.
        return (a << k);
    }

