    public static int gcd(int a, int b) {
        // Base case: if a and b are equal, their GCD is a (or b).
        if (a == b) {
            return a;
        }
        // Base case: if a is 0, GCD is b.
        if (a == 0) {
            return b;
        }
        // Base case: if b is 0, GCD is a.
        if (b == 0) {
            return a;
        }
        // (~a & 1) == 1 is a bitwise check for a being even.
        // It's equivalent to (a & 1) == 0.
        if ((~a & 1) == 1) {
            // (b & 1) == 1 checks if b is odd.
            if ((b & 1) == 1) {
                // a is even, b is odd: gcd(a, b) = gcd(a/2, b)
                return gcd(a >> 1, b);
            } else {
                // Both a and b are even: gcd(a, b) = 2 * gcd(a/2, b/2)
                return (gcd(a >> 1, b >> 1) << 1);
            }
        }
        // (~b & 1) == 1 checks if b is even.
        // At this point, we know a is odd.
        if ((~b & 1) == 1) {
            // a is odd, b is even: gcd(a, b) = gcd(a, b/2)
            return gcd(a, b >> 1);
        }
        // At this point, both a and b are odd.
        if (a > b) {
            // gcd(a, b) = gcd((a-b)/2, b)
            return gcd((a - b) >> 1, b);
        }
        // gcd(a, b) = gcd((b-a)/2, a)
        return gcd((b - a) >> 1, a);
